-- 1.1 Source table row count
SELECT 
    'Source Table Total' AS check_name,
    COUNT(*) AS row_count,
    'Expected: > 0' AS expected_result
FROM dev.dna_approved.renewal_360;

-- 1.2 CTE 1 - Cancelled expirations row count
SELECT 
    'CTE1 - Cancelled Expirations' AS check_name,
    COUNT(*) AS row_count,
    'Expected: > 0' AS expected_result
FROM (
    SELECT DISTINCT resource_id, prior_bill_shopper_id, product_family_name, 
        prior_bill_product_pnl_group_name, prior_bill_product_pnl_line_name, 
        prior_bill_product_pnl_Category_name, prior_bill_product_pnl_subline_name,
        prior_bill_product_pnl_version_name, entitlement_cancel_mst_date
    FROM dev.dna_approved.renewal_360
    WHERE entitlement_cancel_mst_date IS NOT NULL 
        AND bill_exclude_reason_desc IS NULL
        AND LOWER(prior_bill_product_pnl_group_name) <> 'domains'
        AND prior_bill_primary_product_flag = TRUE
        AND entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60
) cte1;

-- 1.3 CTE 2 - New orders row count
SELECT 
    'CTE2 - New Orders' AS check_name,
    COUNT(*) AS row_count,
    'Expected: > 0' AS expected_result
FROM (
    SELECT DISTINCT resource_id, prior_bill_modified_mst_date, prior_bill_shopper_id, 
        product_family_name, prior_bill_product_pnl_group_name,
        prior_bill_product_pnl_Category_name, prior_bill_product_pnl_line_name, 
        prior_bill_product_pnl_subline_name, prior_bill_product_pnl_version_name
    FROM dev.dna_approved.renewal_360
    WHERE prior_bill_modified_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 1
        AND bill_exclude_reason_desc IS NULL 
        AND prior_bill_product_pnl_new_renewal_name = 'New Purchase' 
        AND prior_bill_sequence_number = 1
        AND prior_bill_primary_product_flag = TRUE
        AND LOWER(prior_bill_product_pnl_group_name) <> 'domains'
) cte2;

-- 1.4 Final table row count
SELECT 
    'Final Table - cancel_rebuy' AS check_name,
    COUNT(*) AS row_count,
    'Expected: Should match CTE1 count' AS expected_result
FROM ba_ecommerce.cancel_rebuy;

