   OR cancel_rebuy_product_pnl_version_flag IS NULL;

-- ========================================================================
-- 3. DUPLICATE DETECTION QUERIES
-- ========================================================================

-- 3.1 Check for duplicate resource_ids (should be unique per combination)
SELECT 
    'Duplicate Check - Primary Key' AS check_name,
    COUNT(*) AS duplicate_count,
    'Expected: 0' AS expected_result
FROM (
    SELECT resource_id, product_family_name, prior_bill_shopper_id, entitlement_cancel_mst_date,
           COUNT(*) AS occurrence_count
    FROM ba_ecommerce.cancel_rebuy
    GROUP BY resource_id, product_family_name, prior_bill_shopper_id, entitlement_cancel_mst_date
    HAVING COUNT(*) > 1
);

-- 3.2 Show any duplicate records if they exist
SELECT 
    'Duplicate Records Detail' AS check_name,
    resource_id, 
    product_family_name, 
    prior_bill_shopper_id, 
    entitlement_cancel_mst_date,
    COUNT(*) AS duplicate_count
FROM ba_ecommerce.cancel_rebuy
GROUP BY resource_id, product_family_name, prior_bill_shopper_id, entitlement_cancel_mst_date
HAVING COUNT(*) > 1
ORDER BY duplicate_count DESC
LIMIT 100;

-- ========================================================================
-- 4. JOIN VALIDATION (CHECK FOR ORPHANED RECORDS)
-- ========================================================================

-- 4.1 Verify all CTE1 records made it to final table
WITH cte1 AS (
    SELECT DISTINCT resource_id, prior_bill_shopper_id, product_family_name, 
        entitlement_cancel_mst_date
    FROM dev.dna_approved.renewal_360
    WHERE entitlement_cancel_mst_date IS NOT NULL 
        AND bill_exclude_reason_desc IS NULL
        AND LOWER(prior_bill_product_pnl_group_name) <> 'domains'
        AND prior_bill_primary_product_flag = TRUE
        AND entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60
)
SELECT 
    'Join Validation - Missing CTE1 Records' AS check_name,
    COUNT(*) AS missing_count,
    'Expected: 0' AS expected_result
FROM cte1
LEFT JOIN ba_ecommerce.cancel_rebuy cr
    ON cte1.resource_id = cr.resource_id
    AND cte1.prior_bill_shopper_id = cr.prior_bill_shopper_id
    AND cte1.product_family_name = cr.product_family_name
    AND cte1.entitlement_cancel_mst_date = cr.entitlement_cancel_mst_date
WHERE cr.resource_id IS NULL;

-- 4.2 Check join cardinality - verify no unexpected expansion
WITH cte1_count AS (
    SELECT COUNT(DISTINCT resource_id) AS cte1_distinct_resources
    FROM dev.dna_approved.renewal_360
    WHERE entitlement_cancel_mst_date IS NOT NULL 
        AND bill_exclude_reason_desc IS NULL
        AND LOWER(prior_bill_product_pnl_group_name) <> 'domains'
        AND prior_bill_primary_product_flag = TRUE
        AND entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60
),
final_count AS (
    SELECT COUNT(DISTINCT resource_id) AS final_distinct_resources
    FROM ba_ecommerce.cancel_rebuy
)
SELECT 
    'Join Cardinality Check' AS check_name,
    cte1_distinct_resources,
    final_distinct_resources,
    'Expected: Should be similar, final may be less due to grouping' AS expected_result
FROM cte1_count, final_count;

-- ========================================================================
-- 5. BUSINESS RULE VALIDATION
-- ========================================================================

-- 5.1 Validate date range for entitlement_cancel_mst_date
SELECT 
    'Business Rule - Cancel Date Range' AS check_name,
    COUNT(*) AS violation_count,
    'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE entitlement_cancel_mst_date < '2024-01-01'
   OR entitlement_cancel_mst_date > CURRENT_DATE - 60;

-- 5.2 Validate flag values (should only be 0 or 1)
SELECT 
    'Business Rule - Flag Values' AS check_name,
    COUNT(*) AS violation_count,
    'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE cancel_rebuy_flag NOT IN (0, 1)
   OR cancel_rebuy_product_pnl_group_flag NOT IN (0, 1)
   OR cancel_rebuy_product_pnl_category_flag NOT IN (0, 1)
   OR cancel_rebuy_product_pnl_line_flag NOT IN (0, 1)
   OR cancel_rebuy_product_pnl_version_flag NOT IN (0, 1);

-- 5.3 Validate flag hierarchy logic
-- If cancel_rebuy_flag = 0, all other flags should be 0
SELECT 
    'Business Rule - Flag Hierarchy' AS check_name,
    COUNT(*) AS violation_count,
    'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE cancel_rebuy_flag = 0
  AND (cancel_rebuy_product_pnl_group_flag = 1
       OR cancel_rebuy_product_pnl_category_flag = 1
       OR cancel_rebuy_product_pnl_line_flag = 1
       OR cancel_rebuy_product_pnl_version_flag = 1);

-- 5.4 Validate more specific flags are subset of less specific flags
SELECT 
    'Business Rule - Flag Subset Logic' AS check_name,
    COUNT(*) AS violation_count,
    'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE cancel_rebuy_product_pnl_version_flag = 1
  AND (cancel_rebuy_product_pnl_group_flag = 0
       OR cancel_rebuy_product_pnl_line_flag = 0
       OR cancel_rebuy_flag = 0);

-- 5.5 Verify domains are excluded (validate filter)
WITH source_check AS (
    SELECT resource_id, prior_bill_shopper_id, product_family_name
    FROM dev.dna_approved.renewal_360
    WHERE entitlement_cancel_mst_date IS NOT NULL 
        AND bill_exclude_reason_desc IS NULL
        AND LOWER(prior_bill_product_pnl_group_name) = 'domains'
        AND prior_bill_primary_product_flag = TRUE
        AND entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60
)
SELECT 
    'Business Rule - Domains Excluded' AS check_name,
    COUNT(*) AS violation_count,
    'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy cr
INNER JOIN source_check sc
    ON cr.resource_id = sc.resource_id
    AND cr.prior_bill_shopper_id = sc.prior_bill_shopper_id
    AND cr.product_family_name = sc.product_family_name;

-- ========================================================================
-- 6. DATA TYPE VALIDATION
-- ========================================================================

-- 6.1 Verify resource_id format (assuming it should be non-empty string)
SELECT 
    'Data Type - resource_id Format' AS check_name,
    COUNT(*) AS violation_count,
    'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE resource_id = '' 
   OR TRIM(resource_id) = '';

-- 6.2 Verify date column is valid date
SELECT 
    'Data Type - Valid Cancel Date' AS check_name,
    COUNT(*) AS violation_count,
    'Expected: 0' AS expected_result
FROM ba_ecommerce.cancel_rebuy
WHERE TRY_CAST(entitlement_cancel_mst_date AS DATE) IS NULL;

-- ========================================================================
-- 7. AGGREGATE METRIC VERIFICATION
-- ========================================================================

-- 7.1 Distribution of records by cancel_rebuy_flag
SELECT 
    'Metric - Cancel Rebuy Flag Distribution' AS metric_name,
    cancel_rebuy_flag,
    COUNT(*) AS record_count,
    ROUND(100.0 * COUNT(*) / SUM(COUNT(*)) OVER(), 2) AS percentage
FROM ba_ecommerce.cancel_rebuy
GROUP BY cancel_rebuy_flag
ORDER BY cancel_rebuy_flag;

-- 7.2 Distribution by product family
SELECT 
    'Metric - Top 10 Product Families' AS metric_name,
    product_family_name,
    COUNT(*) AS cancellation_count,
    SUM(cancel_rebuy_flag) AS rebuy_count,
    ROUND(100.0 * SUM(cancel_rebuy_flag) / COUNT(*), 2) AS rebuy_rate
FROM ba_ecommerce.cancel_rebuy
GROUP BY product_family_name
ORDER BY cancellation_count DESC
LIMIT 10;

-- 7.3 Flag combination analysis
SELECT 
    'Metric - Flag Combinations' AS metric_name,
    cancel_rebuy_flag,
    cancel_rebuy_product_pnl_group_flag,
    cancel_rebuy_product_pnl_category_flag,
    cancel_rebuy_product_pnl_line_flag,
    cancel_rebuy_product_pnl_version_flag,
    COUNT(*) AS record_count
FROM ba_ecommerce.cancel_rebuy
GROUP BY 
    cancel_rebuy_flag,
    cancel_rebuy_product_pnl_group_flag,
    cancel_rebuy_product_pnl_category_flag,
    cancel_rebuy_product_pnl_line_flag,
    cancel_rebuy_product_pnl_version_flag
ORDER BY record_count DESC
LIMIT 20;

-- 7.4 Monthly cancellation trend
SELECT 
    'Metric - Monthly Cancellation Trend' AS metric_name,
    DATE_TRUNC('month', entitlement_cancel_mst_date) AS cancel_month,
    COUNT(*) AS total_cancellations,
    SUM(cancel_rebuy_flag) AS rebuys,
    ROUND(100.0 * SUM(cancel_rebuy_flag) / COUNT(*), 2) AS rebuy_rate
FROM ba_ecommerce.cancel_rebuy
GROUP BY DATE_TRUNC('month', entitlement_cancel_mst_date)
ORDER BY cancel_month;

-- 7.5 Rebuy timing distribution (for records with rebuy)
WITH cte AS (
    SELECT DISTINCT r.resource_id, r.prior_bill_shopper_id, r.product_family_name, 
        r.entitlement_cancel_mst_date
    FROM dev.dna_approved.renewal_360 r
    WHERE r.entitlement_cancel_mst_date IS NOT NULL 
        AND r.bill_exclude_reason_desc IS NULL
        AND LOWER(r.prior_bill_product_pnl_group_name) <> 'domains'
        AND r.prior_bill_primary_product_flag = TRUE
        AND r.entitlement_cancel_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 60
),
cte_2 AS (
    SELECT DISTINCT r.resource_id, r.prior_bill_modified_mst_date, 
        r.prior_bill_shopper_id, r.product_family_name
    FROM dev.dna_approved.renewal_360 r
    WHERE r.prior_bill_modified_mst_date BETWEEN '2024-01-01' AND CURRENT_DATE - 1
        AND r.bill_exclude_reason_desc IS NULL 
        AND r.prior_bill_product_pnl_new_renewal_name = 'New Purchase' 
        AND r.prior_bill_sequence_number = 1
        AND r.prior_bill_primary_product_flag = TRUE
        AND LOWER(r.prior_bill_product_pnl_group_name) <> 'domains'
)
SELECT 
    'Metric - Rebuy Timing Distribution' AS metric_name,
    DATEDIFF(day, cte.entitlement_cancel_mst_date, cte_2.prior_bill_modified_mst_date) AS days_to_rebuy,
    COUNT(*) AS rebuy_count
FROM cte
INNER JOIN cte_2
    ON cte.prior_bill_shopper_id = cte_2.prior_bill_shopper_id
    AND cte.product_family_name = cte_2.product_family_name
    AND cte_2.prior_bill_modified_mst_date BETWEEN DATEADD(day, 30, cte.entitlement_cancel_mst_date)
        AND DATEADD(day, 60, cte.entitlement_cancel_mst_date)
GROUP BY DATEDIFF(day, cte.entitlement_cancel_mst_date, cte_2.prior_bill_modified_mst_date)
ORDER BY days_to_rebuy;

-- 7.6 Summary statistics
SELECT 
    'Summary Statistics' AS metric_name,
    COUNT(*) AS total_records,
    COUNT(DISTINCT resource_id) AS distinct_resources,
    COUNT(DISTINCT prior_bill_shopper_id) AS distinct_shoppers,
    COUNT(DISTINCT product_family_name) AS distinct_product_families,
    SUM(cancel_rebuy_flag) AS total_rebuys,
    ROUND(100.0 * SUM(cancel_rebuy_flag) / COUNT(*), 2) AS overall_rebuy_rate,
    MIN(entitlement_cancel_mst_date) AS earliest_cancel_date,
    MAX(entitlement_cancel_mst_date) AS latest_cancel_date
FROM ba_ecommerce.cancel_rebuy;

-- ========================================================================
-- 8. COMPREHENSIVE VALIDATION SUMMARY
-- ========================================================================

SELECT 
    'VALIDATION COMPLETE' AS status,
    CURRENT_TIMESTAMP AS validation_timestamp,
    'Review all checks above - Expected violations should be 0' AS note;
